{
 "style": "Moody scratchboard linework over salt-bleached ink washes, a woodcut left out in weather.",
 "palette": "Iron grey and lamp-oil gold against deep tidal green-black.",
 "influences": [
  "maritime folk-horror illustration",
  "scrimshaw linework"
 ],
 "notes": "The lamp is the only reliable light source in every plate.",
 "profiles": [
