   "entity": "character:cartographer",
   "appearance": "A trim, watchful man with a tidy beard going salt-and-pepper and ink-stained cuffs from chart work.",
   "iconography": [
    "ink-stained cuffs",
    "a chart case at the hip",
    "a sounding line"
   ]
  },
  {
   "entity": "character:keeper",
   "appearance": "A weathered woman in an oilskin coat, hands roped with old calluses, economical in her movements.",
   "iconography": [
    "the oilskin coat",
    "the lamp gimbal"
   ]
  },
  {
   "entity": "character:sleeper",
   "appearance": "Never rendered whole: a shadow the size of weather, suggested only by displaced water at the frame's edge.",
   "iconography": [
    "a shape the size of weather",
    "water that moves wrong"
   ]
  },
  {
   "entity": "location:lighthouse",
   "appearance": "A lighthouse on iron stilts above the shoals, its lamp room a small warm box of brass against the dark.",
